  1	import {
  2	  Button,
  3	  MenuToggle,
  4	  MenuToggleElement,
  5	  Select,
  6	  SelectList,
  7	  SelectOption,
  8	  SelectOptionProps,
  9	  TextInputGroup,
 10	  TextInputGroupMain,
 11	  TextInputGroupUtilities,
 12	} from '@patternfly/react-core';
 13	import { TimesIcon } from '@patternfly/react-icons';
 14	import React from 'react';
 15	
 16	const NO_RESULTS = 'no results';
 17	
 18	interface TypeaheadSelectProps {
 19	  options: SelectOptionProps[];
 20	  onSelect: (value: string | undefined) => void;
 21	  placeholder?: string;
 22	}
 23	
 24	export const TypeaheadSelect: React.FC<TypeaheadSelectProps> = ({
 25	  options,
 26	  onSelect,
 27	  placeholder,
 28	}) => {
 29	  const [isOpen, setIsOpen] = React.useState(false);
 30	  const [selected, setSelected] = React.useState('');
 31	  const [inputValue, setInputValue] = React.useState<string>('');
 32	  const [selectOptions, setSelectOptions] = React.useState<SelectOptionProps[]>(options);
 33	  const [focusedItemIndex, setFocusedItemIndex] = React.useState<number | null>(null);
 34	  const [activeItemId, setActiveItemId] = React.useState<string | null>(null);
 35	  const [filterValue, setFilterValue] = React.useState<string>('');
 36	  const textInputRef = React.useRef<HTMLInputElement>();
 37	
 38	  React.useEffect(() => {
 39	    let newSelectOptions: SelectOptionProps[] = options;
 40	
 41	    if (filterValue) {
 42	      newSelectOptions = options.filter((menuItem) =>
 43	        String(menuItem.name).toLowerCase().includes(filterValue.toLowerCase()),
 44	      );
 45	
 46	      if (!newSelectOptions.length) {
 47	        newSelectOptions = [
 48	          {
 49	            isAriaDisabled: true,
 50	            name: `No results found for "${filterValue}"`,
 51	            value: NO_RESULTS,
 52	          },
 53	        ];
 54	      }
 55	
 56	      if (!isOpen) {
 57	        setIsOpen(true);
 58	      }
 59	    }
 60	
 61	    setSelectOptions(newSelectOptions);
 62	    // eslint-disable-next-line react-hooks/exhaustive-deps
 63	  }, [filterValue, options]);
 64	
 65	  const handleSelect = (
 66	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
 67	    value: string | undefined,
 68	  ) => {
 69	    if (!value) {
 70	      setSelected(undefined);
 71	      setIsOpen(false);
 72	      return;
 73	    }
 74	    setSelected(value);
 75	    setInputValue('');
 76	    setIsOpen(false);
 77	    setSelectOptions(options);
 78	    onSelect(value);
 79	  };
 80	
 81	  const resetActiveAndFocusedItem = () => {
 82	    setFocusedItemIndex(null);
 83	    setActiveItemId(null);
 84	  };
 85	
 86	  const closeMenu = () => {
 87	    setIsOpen(false);
 88	    resetActiveAndFocusedItem();
 89	  };
 90	
 91	  const onToggleClick = () => {
 92	    setIsOpen(!isOpen);
 93	    textInputRef?.current?.focus();
 94	  };
 95	
 96	  const onClearButtonClick = () => {
 97	    setSelected('');
 98	    setInputValue('');
 99	    setFilterValue('');
100	    resetActiveAndFocusedItem();
101	    textInputRef?.current?.focus();
102	  };
103	
104	  const onInputClick = () => {
105	    if (!isOpen) {
106	      setIsOpen(true);
107	    } else if (!inputValue) {
108	      closeMenu();
109	    }
110	  };
111	
112	  const onTextInputChange = (_event: React.FormEvent<HTMLInputElement>, value: string) => {
113	    setInputValue(value);
114	    setFilterValue(value);
115	
116	    resetActiveAndFocusedItem();
117	
118	    if (value !== selected) {
119	      setSelected('');
120	    }
121	  };
122	
123	  const selectOption = (value: string, content: string | number) => {
124	    onSelect(value);
125	    setInputValue(String(content));
126	    setFilterValue('');
127	    setSelected(String(value));
128	
129	    closeMenu();
130	  };
131	
132	  const onInputKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
133	    const focusedItem = focusedItemIndex !== null ? selectOptions[focusedItemIndex] : null;
134	
135	    switch (event.key) {
136	      case 'Enter':
137	        if (
138	          isOpen &&
139	          focusedItem &&
140	          focusedItem.value !== NO_RESULTS &&
141	          !focusedItem.isAriaDisabled
142	        ) {
143	          selectOption(focusedItem.value, focusedItem.name);
144	        }
145	
146	        if (!isOpen) {
147	          setIsOpen(true);
148	        }
149	
150	        break;
151	      case 'ArrowUp':
152	      case 'ArrowDown':
153	        event.preventDefault();
154	        handleMenuArrowKeys(event.key);
155	        break;
156	    }
157	  };
158	
159	  const setActiveAndFocusedItem = (itemIndex: number) => {
160	    setFocusedItemIndex(itemIndex);
161	    const focusedItem = selectOptions[itemIndex];
162	    setActiveItemId(focusedItem.name);
163	  };
164	
165	  const handleMenuArrowKeys = (key: string) => {
166	    let indexToFocus = 0;
167	
168	    if (!isOpen) {
169	      setIsOpen(true);
170	    }
171	
172	    if (selectOptions.every((option) => option.isDisabled)) {
173	      return;
174	    }
175	
176	    if (key === 'ArrowUp') {
177	      if (focusedItemIndex === null || focusedItemIndex === 0) {
178	        indexToFocus = selectOptions.length - 1;
179	      } else {
180	        indexToFocus = focusedItemIndex - 1;
181	      }
182	
183	      // Skip disabled options
184	      while (selectOptions[indexToFocus].isDisabled) {
185	        indexToFocus--;
186	        if (indexToFocus === -1) {
187	          indexToFocus = selectOptions.length - 1;
188	        }
189	      }
190	    }
191	
192	    if (key === 'ArrowDown') {
193	      if (focusedItemIndex === null || focusedItemIndex === selectOptions.length - 1) {
194	        indexToFocus = 0;
195	      } else {
196	        indexToFocus = focusedItemIndex + 1;
197	      }
198	
199	      // Skip disabled options
200	      while (selectOptions[indexToFocus].isDisabled) {
201	        indexToFocus++;
202	        if (indexToFocus === selectOptions.length) {
203	          indexToFocus = 0;
204	        }
205	      }
206	    }
207	
208	    setActiveAndFocusedItem(indexToFocus);
209	  };
210	
211	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
212	    <MenuToggle
213	      ref={toggleRef}
214	      variant="typeahead"
215	      aria-label="Typeahead menu toggle"
216	      onClick={onToggleClick}
217	      isExpanded={isOpen}
218	      isFullWidth
219	    >
220	      <TextInputGroup isPlain>
221	        <TextInputGroupMain
222	          value={inputValue}
223	          onClick={onInputClick}
224	          onChange={onTextInputChange}
225	          onKeyDown={onInputKeyDown}
226	          id="query-select-typeahead-input"
227	          autoComplete="off"
228	          innerRef={textInputRef}
229	          placeholder={placeholder}
230	          {...(activeItemId && { 'aria-activedescendant': activeItemId })}
231	          role="combobox"
232	          isExpanded={isOpen}
233	          aria-controls="select-typeahead-listbox"
234	        />
235	
236	        <TextInputGroupUtilities {...(!inputValue ? { style: { display: 'none' } } : {})}>
237	          <Button variant="plain" onClick={onClearButtonClick} aria-label="Clear input value">
238	            <TimesIcon aria-hidden />
239	          </Button>
240	        </TextInputGroupUtilities>
241	      </TextInputGroup>
242	    </MenuToggle>
243	  );
244	
245	  return (
246	    <Select
247	      id="typeahead-select"
248	      isOpen={isOpen}
249	      onSelect={handleSelect}
250	      onOpenChange={(isOpen) => {
251	        !isOpen && closeMenu();
252	      }}
253	      toggle={toggle}
254	      shouldFocusFirstItemOnOpen={false}
255	    >
256	      <SelectList>
257	        {selectOptions.map((option, index) => (
258	          <SelectOption
259	            key={`${option.name} ${index}`}
260	            isFocused={focusedItemIndex === index}
261	            id={option.name}
262	            value={option.value}
263	            isDisabled={option.isAriaDisabled}
264	          >
265	            {option.name}
266	          </SelectOption>
267	        ))}
268	      </SelectList>
269	    </Select>
270	  );
271	};

